// src/pages/FarmEditPage.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css'; // Sử dụng CSS chung hoặc CSS của form
import './FormPage.css'; // Đảm bảo bạn có CSS này nếu dùng các class form-group, form-container

function FarmEditPage() {
  const { farmId } = useParams(); // Lấy farmId từ URL
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const [farmData, setFarmData] = useState(null); // <--- THAY ĐỔI: Khởi tạo là null
                                                // Thay vì đối tượng rỗng, để dễ kiểm tra trạng thái tải
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  useEffect(() => {
    const fetchFarm = async () => {
      try {
        setLoading(true);
        setError(''); // Xóa lỗi cũ khi tải lại

        const response = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
          headers: { Authorization: `Bearer ${token}` }
        });

        // Kiểm tra xem dữ liệu có tồn tại không
        if (response.data) {
          setFarmData(response.data);
        } else {
          // Nếu API trả về 200 OK nhưng data là rỗng/null, báo lỗi
          setError('Không tìm thấy thông tin cơ sở nuôi này hoặc dữ liệu trả về không hợp lệ.');
          setFarmData(null); // Đặt lại về null để hiển thị thông báo lỗi
        }

      } catch (err) {
        setError('Không thể tải thông tin cơ sở nuôi. Vui lòng thử lại.');
        console.error('Lỗi khi tải thông tin farm:', err);
        setFarmData(null); // Đặt lại về null khi có lỗi
      } finally {
        setLoading(false);
      }
    };

    if (farmId && token) { // Chỉ fetch khi có farmId và token
      fetchFarm();
    } else if (!farmId) {
      setError('Không có ID cơ sở nuôi để chỉnh sửa.');
      setLoading(false);
    } else if (!token) {
      setError('Bạn cần đăng nhập để chỉnh sửa cơ sở nuôi.');
      setLoading(false);
      navigate('/'); // Chuyển hướng về trang đăng nhập nếu không có token
    }

  }, [farmId, token, navigate]); // Thêm navigate vào dependency array

  // Hàm xử lý thay đổi input
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFarmData(prevData => ({
      ...prevData,
      [name]: value
    }));
  };

  // Hàm xử lý gửi form
  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      await axios.put(`http://localhost:10000/api/farms/${farmId}`, farmData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setMessage('Cập nhật thông tin cơ sở nuôi thành công!');
      // Có thể chuyển hướng sau khi cập nhật thành công nếu muốn
      // navigate('/admin/farms');
    } catch (err) {
      console.error('Lỗi khi cập nhật farm:', err);
      setError(err.response?.data?.message || 'Cập nhật thất bại. Vui lòng thử lại.');
    }
  };

  // ----- Conditional rendering -----
  if (loading) {
    return (
      <div className="form-container">
        <p>Đang tải thông tin cơ sở nuôi...</p>
      </div>
    );
  }

  if (error) { // Hiển thị lỗi nếu có
    return (
      <div className="form-container">
        <p style={{ color: 'red' }}>Lỗi: {error}</p>
        <button onClick={() => navigate('/admin/farms')}>Quay lại danh sách</button>
      </div>
    );
  }

  // <--- QUAN TRỌNG: Chỉ render form khi farmData đã có dữ liệu
  if (!farmData) { // Nếu farmData là null sau khi tải và không có lỗi cụ thể
    return (
        <div className="form-container">
            <p style={{ color: 'orange' }}>Không tìm thấy thông tin cơ sở nuôi.</p>
            <button onClick={() => navigate('/admin/farms')}>Quay lại danh sách</button>
        </div>
    );
  }

  return (
    <div className="form-container">
      <h2>✏️ Chỉnh sửa thông tin cơ sở nuôi</h2>
      {message && <p style={{ color: 'green' }}>{message}</p>}
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>Tên cơ sở:</label>
          <input
            type="text"
            name="tenCoSo"
            value={farmData.tenCoSo || ''} // Đảm bảo giá trị không phải null/undefined
            onChange={handleChange}
            required
          />
        </div>
        <div className="form-group">
          <label>Tỉnh:</label>
          <input
            type="text"
            name="tinh"
            value={farmData.tinh || ''}
            onChange={handleChange}
            required
          />
        </div>
        <div className="form-group">
          <label>Huyện:</label>
          <input
            type="text"
            name="huyen"
            value={farmData.huyen || ''}
            onChange={handleChange}
            required
          />
        </div>
        <div className="form-group">
          <label>Xã:</label>
          <input
            type="text"
            name="xa"
            value={farmData.xa || ''}
            onChange={handleChange}
            required
          />
        </div>
        <div className="form-group">
          <label>Chủ trại:</label>
          <input
            type="text"
            name="chuTrai"
            value={farmData.chuTrai || ''}
            onChange={handleChange}
            required
          />
        </div>
        <div className="form-group">
          <label>Số điện thoại:</label>
          <input
            type="text"
            name="soDienThoai"
            value={farmData.soDienThoai || ''}
            onChange={handleChange}
          />
        </div>
        {/* Thêm các trường khác tương ứng với mô hình dữ liệu farm của bạn */}
        <button type="submit" className="submit-button">Lưu thay đổi</button>
        <button type="button" className="cancel-button" onClick={() => navigate('/admin/farms')}>
          Hủy
        </button>
      </form>
    </div>
  );
}

export default FarmEditPage;
